PATCH /agent/{id}.sdkCallSource:
client.agent.patch("id", [
            {
                op: "replace",
                path: "/description",
                value: "patched description",
            },
            {
                op: "add",
                path: "/tags/-",
                value: "updated",
            },
        ])

PATCH /agent/prompts/{id}.sdkCallSource:
client.agent.prompts.patch("id", [
            {
                op: "replace",
                path: "/content",
                value: "Updated prompt content.",
            },
        ])

POST /cohort.sdkCallSource:
client.cohort.analyze({
            text: "female patients over 65 with diabetes but not hypertension",
        })

POST /construe/upload.sdkCallSource:
client.construe.uploadCodeSystem({
            name: "CUSTOM_CODES",
            version: "1.0",
            format: "json",
            codes: [
                {
                    code: "X001",
                    description: "Example custom code 1",
                },
                {
                    code: "X002",
                    description: "Example custom code 2",
                },
            ],
        })

POST /construe/extract.sdkCallSource:
client.construe.extractCodes({
            text: "Patient is a 14-year-old female, previously healthy, who is here for evaluation of abnormal renal ultrasound with atrophic right kidney.",
            system: {
                name: "ICD-10-CM",
                version: "2025",
            },
        })

GET /construe/codes/{codesystem}/search/.sdkCallSource:
client.construe.semanticSearchEmbeddingBased("ICD-10-CM", {
            text: "patient has trouble breathing at night and wakes up gasping",
            version: "version",
            limit: 1,
        })

POST /construe/feedback.sdkCallSource:
client.construe.submitFeedbackOnExtractionResults({
            text: "Patient has type 2 diabetes with hyperglycemia",
            received_result: {
                system: {
                    name: "ICD-10-CM",
                    version: "2025",
                },
                codes: [
                    {
                        code: "E11.9",
                        description: "Type 2 diabetes mellitus without complications",
                        valid: true,
                    },
                ],
            },
            expected_result: {
                system: {
                    name: "ICD-10-CM",
                    version: "2025",
                },
                codes: [
                    {
                        code: "E11.65",
                        description: "Type 2 diabetes mellitus with hyperglycemia",
                        valid: true,
                    },
                ],
            },
            detail: "Expected code E11.65 because the text mentions hyperglycemia",
        })

